'use server'

import { createClient } from "@/utils/supabase/server"
import { revalidatePath } from "next/cache"
import { redirect } from "next/navigation"

export async function deleteProduct(formData: FormData) {
    const productId = formData.get('productId') as string

    if (!productId) return

    const supabase = await createClient()
    const { data: { user } } = await supabase.auth.getUser()

    if (!user) return redirect('/auth/login')

    // RLS policies already check if user is owner, but good to be explicit
    const { error } = await supabase
        .from('products')
        .delete()
        .eq('id', productId)
        .eq('seller_id', user.id)

    if (error) {
        console.error('Error deleting product:', error)
        return
    }

    revalidatePath('/vendedor/dashboard')
    revalidatePath('/vendedor/dashboard')
    revalidatePath('/') // Update home feed too
}

export async function updateProfile(formData: FormData) {
    const whatsapp = formData.get('whatsapp') as string
    const location = formData.get('location') as string

    // Basic validation
    if (!whatsapp) return

    const supabase = await createClient()
    const { data: { user } } = await supabase.auth.getUser()

    if (!user) return redirect('/auth/login')

    const { error } = await supabase
        .from('profiles')
        .update({
            whatsapp,
            current_location: location
        })
        .eq('id', user.id)

    if (error) {
        console.error('Error updating profile:', error)
        return redirect('/vendedor/perfil?error=true')
    }

    revalidatePath('/vendedor/perfil')
    redirect('/vendedor/perfil?success=true')
}

export async function toggleOnlineStatus(isOnline: boolean) {
    const supabase = await createClient()
    const { data: { user } } = await supabase.auth.getUser()

    if (!user) return

    const { error } = await supabase
        .from('profiles')
        .update({ is_online: isOnline })
        .eq('id', user.id)

    if (error) {
        console.error('Error toggling online status:', error)
        return
    }

    revalidatePath('/vendedor/dashboard')
    revalidatePath('/')
}

export async function updateLocation(location: string) {
    const supabase = await createClient()
    const { data: { user } } = await supabase.auth.getUser()

    if (!user) return

    const { error } = await supabase
        .from('profiles')
        .update({ current_location: location })
        .eq('id', user.id)

    if (error) {
        console.error('Error updating location:', error)
        return
    }

    revalidatePath('/vendedor/perfil')
    revalidatePath('/vendedor/dashboard')
    revalidatePath('/')
}

export async function editProduct(formData: FormData) {
    const productId = formData.get('productId') as string
    const name = formData.get('name') as string
    const price = parseFloat(formData.get('price') as string)
    const category = formData.get('category') as string || 'Outros'
    const image = formData.get('image') as File | null

    if (!productId || !name || !price) {
        return redirect('/vendedor/dashboard?error=missing_fields')
    }

    const supabase = await createClient()
    const { data: { user } } = await supabase.auth.getUser()

    if (!user) return redirect('/auth/login')

    let updateData: any = {
        name,
        price,
        category,
    }

    // Handle optional image upload
    if (image && image.size > 0) {
        const fileExt = image.name.split('.').pop()
        const fileName = `${user.id}/${Date.now()}.${fileExt}`
        const { error: uploadError } = await supabase.storage
            .from('products')
            .upload(fileName, image)

        if (!uploadError) {
            const { data: { publicUrl } } = supabase.storage
                .from('products')
                .getPublicUrl(fileName)
            updateData.image = publicUrl
            updateData.image_url = publicUrl
        }
    }

    const { error: dbError } = await supabase
        .from('products')
        .update(updateData)
        .eq('id', productId)
        .eq('seller_id', user.id)

    if (dbError) {
        console.error('DB Update Error:', dbError)
        return redirect('/vendedor/dashboard?error=db_failed')
    }

    revalidatePath('/vendedor/dashboard')
    revalidatePath('/')
    redirect('/vendedor/dashboard')
}

'use client'

import { useState } from "react"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Switch } from "@/components/ui/switch"
import { Button } from "@/components/ui/button"
import Link from "next/link"
import { MapPin } from "lucide-react"
import { toggleOnlineStatus } from "../actions"
import { toast } from "sonner"

interface StoreStatusCardProps {
    initialOnline: boolean
    currentLocation: string | null
}

export function StoreStatusCard({ initialOnline, currentLocation }: StoreStatusCardProps) {
    const [isOnline, setIsOnline] = useState(initialOnline)
    const [loading, setLoading] = useState(false)

    const handleToggle = async (checked: boolean) => {
        setLoading(true)
        setIsOnline(checked)
        try {
            await toggleOnlineStatus(checked)
            toast.success(checked ? "Loja Online!" : "Loja Offline")
        } catch (error) {
            setIsOnline(!checked)
            toast.error("Erro ao atualizar status")
        } finally {
            setLoading(false)
        }
    }

    return (
        <Card>
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                <CardTitle className="text-sm font-medium">
                    Status da Loja
                </CardTitle>
                <Switch
                    id="online-mode"
                    checked={isOnline}
                    onCheckedChange={handleToggle}
                    disabled={loading}
                />
            </CardHeader>
            <CardContent>
                <div className="flex justify-between items-end">
                    <div className="space-y-1">
                        <div className={`text-2xl font-bold ${isOnline ? 'text-green-600' : 'text-muted-foreground'}`}>
                            {isOnline ? 'TÔ ONLINE' : 'TÔ OFFLINE'}
                        </div>
                        <p className="text-xs text-muted-foreground flex items-center gap-1">
                            <MapPin className="h-3 w-3" />
                            {currentLocation || 'Local não definido'}
                        </p>
                    </div>
                    <Button variant="outline" size="sm" asChild>
                        <Link href="/vendedor/perfil">Editar Perfil</Link>
                    </Button>
                </div>
            </CardContent>
        </Card>
    )
}
